99	func TestSlackSender_SemanticReport(t *testing.T) {
100		var received []byte
101		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
102			received, _ = io.ReadAll(r.Body)
103			w.WriteHeader(http.StatusOK)
104		}))
105		defer srv.Close()
106	
107		sender := &SlackSender{Client: srv.Client()}
108		ch := &models.NotificationChannel{
109			Type:   "slack",
110			Config: json.RawMessage(`{"webhook_url": "` + srv.URL + `"}`),
111		}
112	
113		reportJSON := `{
114			"subject": "Ready to Deploy: go-ethereum v1.16.4",
115			"urgency": "High",
116			"urgency_reason": "Security vulnerability patched",
117			"status_checks": ["Binaries Unverified", "Docker Image Unverified"],
118			"changelog_summary": "Security fixes and performance improvements",
119			"availability": "GA",
120			"adoption": "Recommended for production",
121			"recommendation": "Deploy after verifying checksums",
122			"download_commands": ["docker pull ethereum/client-go:v1.16.4"],
123			"download_links": ["https://github.com/ethereum/go-ethereum/releases/tag/v1.16.4"]
124		}`
125	
126		msg := Notification{
127			Title:       "Semantic Release Report: go-ethereum v1.16.4",
128			Body:        reportJSON,
129			Version:     "v1.16.4",
130			ProjectName: "go-ethereum",
131			Provider:    "github",
132			Repository:  "ethereum/go-ethereum",
133			SourceURL:   "https://github.com/ethereum/go-ethereum/releases/tag/v1.16.4",
134			ReleaseURL:  "https://changelogue.example.com/sr/1",
135		}
136	
137		err := sender.Send(context.Background(), ch, msg)
138		if err != nil {
139			t.Fatalf("unexpected error: %v", err)
140		}
141	
142		var payload slackTestPayload
143		if err := json.Unmarshal(received, &payload); err != nil {
144			t.Fatalf("received invalid JSON: %v", err)
145		}
146	
147		// Compact format: header + urgency_reason (High) + changelog + download cmd + context = 5 blocks
148		if len(payload.Blocks) < 3 || len(payload.Blocks) > 6 {
149			t.Fatalf("expected 3-6 blocks for compact semantic report, got %d", len(payload.Blocks))
150		}
151	
152		// First block should be header containing project name, version, and urgency
153		if payload.Blocks[0].Type != "header" {
154			t.Fatalf("expected first block to be header, got %s", payload.Blocks[0].Type)
155		}
156		headerText := payload.Blocks[0].Text.Text
157		if !strings.Contains(headerText, "go-ethereum") || !strings.Contains(headerText, "v1.16.4") {
158			t.Fatalf("header should contain project name and version, got %q", headerText)
159		}
160		if !strings.Contains(headerText, "High") {
161			t.Fatalf("header should contain urgency level, got %q", headerText)
162		}
163	
164		// Should NOT have a fields section (no separate risk/urgency/availability fields)
165		for _, b := range payload.Blocks {
166			if len(b.Fields) > 0 {
167				t.Fatal("compact format should not have field sections")
168			}
169		}
170	
171		// Should have download command
172		hasCode := false
173		for _, b := range payload.Blocks {
174			if b.Text != nil && strings.Contains(b.Text.Text, "docker pull") {
175				hasCode = true
176			}
177		}
178		if !hasCode {
179			t.Fatal("expected download command")
180		}
181	
182		// Last block should be context footer
183		lastBlock := payload.Blocks[len(payload.Blocks)-1]
184		if lastBlock.Type != "context" {
185			t.Fatalf("expected last block to be context, got %s", lastBlock.Type)
186		}
187	}
