// displayVersion strips redundant project-name prefixes from a raw version tag
// for cleaner display. E.g. project "aptos", version "aptos-node-v1.44.2-rc" → "v1.44.2-rc".
func displayVersion(projectName, version string) string {
	if projectName == "" {
		return version
	}
	lower := strings.ToLower(version)
	prefix := strings.ToLower(projectName)
	// Strip project name prefix followed by a separator (e.g. "aptos-node-" from "aptos-node-v1.44.2-rc")
	if strings.HasPrefix(lower, prefix) {
		rest := version[len(prefix):]
		// Skip separators between project name and the meaningful part
		rest = strings.TrimLeft(rest, "-_/")
		// If remainder still has a sub-component prefix (e.g. "node-v1.44.2"), skip it
		// by looking for a version-like pattern (starts with v or digit)
		if len(rest) > 0 && (rest[0] == 'v' || rest[0] == 'V' || (rest[0] >= '0' && rest[0] <= '9')) {
			return rest
		}
		// Try stripping one more component (e.g. "node-v1.44.2" → skip "node-")
		if idx := strings.IndexAny(rest, "-_"); idx >= 0 {
			after := rest[idx+1:]
			if len(after) > 0 && (after[0] == 'v' || after[0] == 'V' || (after[0] >= '0' && after[0] <= '9')) {
				return after
			}
		}
	}
	return version
}

